create extension if not exists pgcrypto;
create table if not exists roles(id uuid primary key default gen_random_uuid(),name text unique not null,description text,created_at timestamptz default now());
create table if not exists permissions(id uuid primary key default gen_random_uuid(),key text unique not null,description text);
create table if not exists role_permissions(role_id uuid references roles(id),permission_id uuid references permissions(id),primary key(role_id,permission_id));
create table if not exists users(id uuid primary key default gen_random_uuid(),email text unique not null,password_hash text not null,display_name text not null,role_id uuid references roles(id),active boolean default true,version int default 1,deleted_at timestamptz,created_at timestamptz default now());
create table if not exists sessions(id uuid primary key default gen_random_uuid(),user_id uuid references users(id),csrf_token text not null,expires_at timestamptz not null,created_at timestamptz default now());
create table if not exists categories(id uuid primary key default gen_random_uuid(),name text unique not null);create table if not exists regions(id uuid primary key default gen_random_uuid(),name text unique not null);
create table if not exists sources(id uuid primary key default gen_random_uuid(),name text not null,url text not null unique,domain text not null,type text not null,category text,region text,language text default 'de',description text,priority int default 0,trust_level int default 50,fetch_interval_seconds int default 900,max_articles int default 20,max_fetch_seconds int default 20,allowed_patterns text[],blocked_patterns text[],requires_javascript boolean default false,user_agent text,license_notes text,last_success_at timestamptz,last_error text,consecutive_errors int default 0,active boolean default true,etag text,last_modified text,version int default 1,deleted_at timestamptz,created_at timestamptz default now());
create table if not exists source_selectors(id uuid primary key default gen_random_uuid(),source_id uuid references sources(id),link_selector text,title_selector text,text_selector text,date_selector text,author_selector text,image_selector text);create table if not exists source_checks(id uuid primary key default gen_random_uuid(),source_id uuid references sources(id),status text not null,details jsonb default '{}',checked_at timestamptz default now());
create table if not exists worker_jobs(id uuid primary key default gen_random_uuid(),kind text not null,payload jsonb not null default '{}',status text not null default 'queued',attempts int default 0,max_attempts int default 5,scheduled_at timestamptz default now(),started_at timestamptz,finished_at timestamptz,error text,locked_at timestamptz,locked_by text);
create index if not exists idx_worker_jobs_claim on worker_jobs(status,scheduled_at);
create table if not exists fetch_jobs(id uuid primary key default gen_random_uuid(),source_id uuid references sources(id),status text not null default 'queued',attempts int default 0,scheduled_at timestamptz default now(),started_at timestamptz,finished_at timestamptz,error text);
create table if not exists article_clusters(id uuid primary key default gen_random_uuid(),title text not null,canonical_key text unique,created_at timestamptz default now());
create table if not exists articles(id uuid primary key default gen_random_uuid(),source_id uuid references sources(id),cluster_id uuid references article_clusters(id),title text not null,url text not null,canonical_url text not null,published_at timestamptz,fetched_at timestamptz default now(),author text,excerpt text,main_text text,content_hash text not null,status text default 'draft',category text,region text,tags text[] default '{}',trust_score int default 50,warnings text[] default '{}',version int default 1,deleted_at timestamptz);
create unique index if not exists idx_articles_canonical_url on articles(canonical_url);
create unique index if not exists idx_articles_content_hash on articles(content_hash);
create unique index if not exists idx_articles_source_hash on articles(source_id,content_hash);
create table if not exists article_versions(id uuid primary key default gen_random_uuid(),article_id uuid references articles(id),snapshot jsonb not null,changed_by uuid references users(id),created_at timestamptz default now());create table if not exists article_entities(id uuid primary key default gen_random_uuid(),article_id uuid references articles(id),type text not null,value text not null);
create table if not exists summaries(id uuid primary key default gen_random_uuid(),article_id uuid references articles(id),source_passages text[],summary text not null,model_name text not null default 'rule-based',model_version text,prompt_version text,confidence int default 60,uncertainties text[],editorial_changes text,created_at timestamptz default now());
create table if not exists scripts(id uuid primary key default gen_random_uuid(),article_id uuid references articles(id),text text not null,screen_text text,ticker_text text,voice_id uuid,created_at timestamptz default now());create table if not exists pronunciations(id uuid primary key default gen_random_uuid(),term text unique not null,pronunciation text not null,language text default 'de');create table if not exists tts_voices(id uuid primary key default gen_random_uuid(),name text not null,engine text not null,model_path text,language text default 'de',gender text,active boolean default true);
create table if not exists media_licenses(id uuid primary key default gen_random_uuid(),name text not null,url text,requires_attribution boolean default true);create table if not exists media_assets(id uuid primary key default gen_random_uuid(),filename text not null,mime_type text not null,size_bytes bigint,resolution text,duration_seconds numeric,source text,author text,license_id uuid references media_licenses(id),original_url text,usage text,expires_at timestamptz,tags text[] default '{}',created_at timestamptz default now());create table if not exists audio_assets(id uuid primary key default gen_random_uuid(),script_id uuid references scripts(id),media_id uuid references media_assets(id),duration_seconds numeric,word_timings jsonb default '[]');
create table if not exists overlay_projects(id uuid primary key default gen_random_uuid(),name text not null,width int default 1920,height int default 1080,created_by uuid references users(id),version int default 1,deleted_at timestamptz,created_at timestamptz default now());create table if not exists overlay_versions(id uuid primary key default gen_random_uuid(),project_id uuid references overlay_projects(id),version int not null,snapshot jsonb not null,published boolean default false,created_at timestamptz default now());create table if not exists overlay_elements(id uuid primary key default gen_random_uuid(),project_id uuid references overlay_projects(id),type text not null,name text not null,x int,y int,width int,height int,rotation numeric default 0,opacity numeric default 1,z_index int default 0,locked boolean default false,hidden boolean default false,props jsonb default '{}',binding text,animation jsonb default '{}');create table if not exists overlay_templates(id uuid primary key default gen_random_uuid(),name text unique not null,category text not null,snapshot jsonb not null);
create table if not exists scene_projects(id uuid primary key default gen_random_uuid(),name text not null,version int default 1,created_at timestamptz default now());create table if not exists scene_versions(id uuid primary key default gen_random_uuid(),scene_id uuid references scene_projects(id),version int,snapshot jsonb,created_at timestamptz default now());create table if not exists scene_sources(id uuid primary key default gen_random_uuid(),scene_id uuid references scene_projects(id),source_type text not null,settings jsonb default '{}',z_index int default 0);
create table if not exists obs_profiles(id uuid primary key default gen_random_uuid(),name text unique not null,settings jsonb default '{}');create table if not exists obs_scene_collections(id uuid primary key default gen_random_uuid(),name text unique not null,settings jsonb default '{}');create table if not exists obs_connections(id uuid primary key default gen_random_uuid(),host text,port int,status text,last_seen_at timestamptz);
create table if not exists broadcast_templates(id uuid primary key default gen_random_uuid(),name text unique not null,flow jsonb not null);create table if not exists broadcast_playlists(id uuid primary key default gen_random_uuid(),name text not null,mode text default 'hybrid',created_at timestamptz default now());create table if not exists broadcast_items(id uuid primary key default gen_random_uuid(),playlist_id uuid references broadcast_playlists(id),article_id uuid references articles(id),position int,duration_seconds int,status text default 'planned',scene_id uuid references scene_projects(id),rules jsonb default '{}');create table if not exists broadcast_runs(id uuid primary key default gen_random_uuid(),playlist_id uuid references broadcast_playlists(id),started_at timestamptz,ended_at timestamptz,status text,last_state jsonb default '{}');create table if not exists stream_profiles(id uuid primary key default gen_random_uuid(),name text,service text,server text,stream_key_encrypted text,video_bitrate_kbps int,audio_bitrate_kbps int,fps int,encoder text,keyframe_interval int);
create table if not exists system_settings(key text primary key,value jsonb not null,updated_at timestamptz default now());create table if not exists notifications(id uuid primary key default gen_random_uuid(),level text,message text,read_at timestamptz,created_at timestamptz default now());create table if not exists audit_logs(id uuid primary key default gen_random_uuid(),user_id uuid references users(id),action text not null,entity_type text,entity_id uuid,details jsonb default '{}',created_at timestamptz default now());create table if not exists errors(id uuid primary key default gen_random_uuid(),component text,severity text,event_type text,details jsonb default '{}',created_at timestamptz default now());create table if not exists health_checks(id uuid primary key default gen_random_uuid(),component text,status text,details jsonb default '{}',checked_at timestamptz default now());create table if not exists backups(id uuid primary key default gen_random_uuid(),path text,status text,size_bytes bigint,checksum text,created_at timestamptz default now());
create index if not exists idx_articles_status on articles(status);create index if not exists idx_articles_fetched_at on articles(fetched_at desc);create index if not exists idx_sources_active on sources(active);create index if not exists idx_audit_entity on audit_logs(entity_type,entity_id);

alter table articles add column if not exists main_text text;
create unique index if not exists idx_articles_content_hash on articles(content_hash);
create table if not exists playback_state(id boolean primary key default true,state jsonb not null default '{}',updated_at timestamptz default now(),constraint playback_state_singleton check (id));
insert into playback_state(id,state) values(true,'{"status":"idle"}'::jsonb) on conflict (id) do nothing;
create index if not exists idx_worker_jobs_claim_locked on worker_jobs(status,scheduled_at,locked_at);

alter table broadcast_playlists add column if not exists status text not null default 'draft';
alter table broadcast_playlists add column if not exists current_position int not null default 0;
alter table broadcast_playlists add column if not exists started_at timestamptz;
alter table broadcast_playlists add column if not exists paused_at timestamptz;
alter table broadcast_playlists add column if not exists ended_at timestamptz;
alter table broadcast_playlists add column if not exists description text;
alter table broadcast_playlists add column if not exists scheduled_at timestamptz;
alter table broadcast_playlists add column if not exists kind text not null default 'playlist';
alter table broadcast_playlists add column if not exists overlay_project_id uuid references overlay_projects(id) on delete set null;
alter table broadcast_playlists add column if not exists settings jsonb not null default '{}';
alter table broadcast_items add column if not exists error text;
alter table broadcast_items add column if not exists started_at timestamptz;
alter table broadcast_items add column if not exists finished_at timestamptz;
create unique index if not exists idx_single_active_broadcast_run on broadcast_runs((true)) where status in ('starting','running','paused','stopping');
create unique index if not exists idx_worker_fetch_source_open on worker_jobs((payload->>'sourceId')) where kind='fetch-source' and status in ('queued','running');
create index if not exists idx_sessions_expires_at on sessions(expires_at);
alter table sessions add column if not exists user_agent text;
alter table sessions add column if not exists ip_address inet;
